import { Link, useNavigate } from "react-router-dom";

const Navbar = () => {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));

  const logout = () => {
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <nav>
      <Link to="/">Home</Link>

      {!user && (
        <>
          <Link to="/login">Login</Link>
          <Link to="/register">Register</Link>
        </>
      )}

      {/* ===== STUDENT LINKS ===== */}
      {user && user.role === "Student" && (
        <>
          <Link to="/student/dashboard">Dashboard</Link>
          <Link to="/books">Books</Link>
          <Link to="/borrowed">Borrowed</Link>
          <Link to="/mybooks">My Books</Link>
          <Link to="/wishlist">Wishlist</Link>
          <Link to="/history">History</Link>
        </>
      )}

      {/* ===== LIBRARIAN LINKS ===== */}
      {user && user.role === "Librarian" && (
        <>
          <Link to="/librarian/dashboard">Dashboard</Link>
          <Link to="/inventory">Inventory</Link>
          <Link to="/add-book">Add Book</Link>
          <Link to="/librarian-books">Books</Link>
          <Link to="/librarian-genre-summary">Genres</Link>
        </>
      )}

      {/* ===== ADMIN LINKS ===== */}
      {user && user.role === "Admin" && (
        <>
          <Link to="/admin/dashboard">Dashboard</Link>
          <Link to="/admin/students">Students</Link>
          <Link to="/admin/manage-librarians">Librarians</Link>
          <Link to="/admin/genres">Genres</Link>
          <Link to="/admin/reports">Reports</Link>
        </>
      )}

      {user && <button onClick={logout}>Logout</button>}
    </nav>
  );
};

export default Navbar;
